args.sparql:
SELECT ?composer ?composerLabel WHERE { 
  ?series wdt:P31 wd:Q147366 ;
          rdfs:label ?seriesLabel .
  FILTER (LANG(?seriesLabel) = 'en') .
  FILTER (CONTAINS(LCASE(?seriesLabel), 'tunnel')) .
  ?series wdt:P86 ?composer .
  ?composer rdfs:label ?composerLabel .
  FILTER (LANG(?composerLabel) = 'en') .
}

SELECT ?composer ?composerLabel WHERE {
  ?series wdt:P31 wd:Q147366 ;
          rdfs:label ?seriesLabel.
  FILTER (LANG(?seriesLabel) = 'en' && CONTAINS(LCASE(?seriesLabel), 'tunnel')).
  ?series wdt:P86 ?composer.
  ?composer rdfs:label ?composerLabel.
  FILTER (LANG(?composerLabel) = 'en').
}

SELECT ?composer ?composerLabel WHERE {
  wd:Q27532865 wdt:P86 ?composer.
  ?composer rdfs:label ?composerLabel.
  FILTER (LANG(?composerLabel) = 'en')
}
